/// View content containing all content necessary to render a view except for
/// runtime input data and the runtime
/// input schema, which is auto-generated by this operation.
pub const ViewInputContent = struct {
    /// A list of possible actions from the view.
    actions: ?[]const []const u8 = null,

    /// The view template representing the structure of the view.
    template: ?[]const u8 = null,

    pub const json_field_names = .{
        .actions = "Actions",
        .template = "Template",
    };
};
